import java.util.Scanner;

public class SafeBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String input = scanner.nextLine();

        // Validate input length before copying to buffer
        if (input.length() > 10) {
            System.out.println("Input exceeds buffer size. Please enter a shorter name.");
            return;
        }

        char[] buffer = new char[10];

        // Copy input to buffer safely
        input.getChars(0, Math.min(input.length(), buffer.length), buffer, 0);

        System.out.println("Hello, " + new String(buffer).trim());
    }
}

### Explanation:
취약유형: Buffer Overflow
